-- MySQL 8 reference; Django migrations remain the executable schema source.
CREATE TABLE IF NOT EXISTS donations_donationproject (id BIGINT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(150) NOT NULL,summary VARCHAR(300) NOT NULL,description LONGTEXT NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',starts_at DATETIME(6) NOT NULL,ends_at DATETIME(6) NOT NULL,created_at DATETIME(6) NOT NULL,updated_at DATETIME(6) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS donations_donationitem (id BIGINT AUTO_INCREMENT PRIMARY KEY,project_id BIGINT NOT NULL,name VARCHAR(100) NOT NULL,unit VARCHAR(20) NOT NULL,required_quantity INT UNSIGNED NOT NULL,sort_order INT UNSIGNED NOT NULL DEFAULT 0,CONSTRAINT uniq_donation_project_item UNIQUE(project_id,name),FOREIGN KEY(project_id) REFERENCES donations_donationproject(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS donations_pledge (id BIGINT AUTO_INCREMENT PRIMARY KEY,user_id BIGINT NOT NULL,item_id BIGINT NOT NULL,quantity INT UNSIGNED NOT NULL,note VARCHAR(255) NOT NULL DEFAULT '',status VARCHAR(20) NOT NULL DEFAULT 'pledged',created_at DATETIME(6) NOT NULL,updated_at DATETIME(6) NOT NULL,INDEX pledge_item_status_idx(item_id,status),FOREIGN KEY(user_id) REFERENCES accounts_user(id),FOREIGN KEY(item_id) REFERENCES donations_donationitem(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
